class Solution {
    public int flipLights(int n, int presses) {
        if (presses == 0) return 1;
        if (n == 1) return presses == 1 ? 2 : 1;
        if (n == 2) return presses <= 2 ? 3 : 2;
        if (n == 3) return presses <= 2 ? 4 : 8;
        if (n == 4) return presses <= 2 ? 8 : 7;
        return presses <= 2 ? 16 : 8;
    }
}
```

